  1	import * as React from 'react';
  2	import CapacityCard, {
  3	  CapacityMetricDatum,
  4	} from '@odf/shared/dashboards/capacity-card/capacity-card';
  5	import { FieldLevelHelp } from '@odf/shared/generic';
  6	import {
  7	  useCustomPrometheusPoll,
  8	  usePrometheusBasePath,
  9	} from '@odf/shared/hooks/custom-prometheus-poll';
 10	import { useWatchStorageSystems } from '@odf/shared/hooks/useWatchStorageSystems';
 11	import { ODFStorageSystem } from '@odf/shared/models';
 12	import { StorageSystemKind } from '@odf/shared/types';
 13	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 14	import { getGVK, humanizeBinaryBytes, referenceFor } from '@odf/shared/utils';
 15	import { PrometheusResponse } from '@openshift-console/dynamic-plugin-sdk';
 16	import * as _ from 'lodash-es';
 17	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
 18	import { storageCapacityTooltip } from '../../../constants';
 19	import { StorageDashboard, CAPACITY_QUERIES } from '../queries';
 20	
 21	const getMetricForSystem = (
 22	  metric: PrometheusResponse,
 23	  system: StorageSystemKind
 24	) =>
 25	  // ToDo (epic 4422): This equality check should work (for now) as "managedBy" will be unique,
 26	  // but moving forward add a label to metric for StorageSystem namespace as well and use that,
 27	  // equality check should be updated with "&&" condition on StorageSystem namespace.
 28	  metric?.data?.result?.find(
 29	    (value) => value.metric.managedBy === system.spec.name
 30	  );
 31	
 32	const SystemCapacityCard: React.FC = () => {
 33	  const { t } = useCustomTranslation();
 34	  const [systems, systemsLoaded, systemsLoadError] = useWatchStorageSystems();
 35	  const [usedCapacity, errorUsedCapacity, loadingUsedCapacity] =
 36	    useCustomPrometheusPoll({
 37	      query: CAPACITY_QUERIES[StorageDashboard.USED_CAPACITY_FILE_BLOCK],
 38	      endpoint: 'api/v1/query' as any,
 39	      basePath: usePrometheusBasePath(),
 40	    });
 41	
 42	  const [totalCapacity, errorTotalCapacity, loadingTotalCapacity] =
 43	    useCustomPrometheusPoll({
 44	      query: CAPACITY_QUERIES[StorageDashboard.TOTAL_CAPACITY_FILE_BLOCK],
 45	      endpoint: 'api/v1/query' as any,
 46	      basePath: usePrometheusBasePath(),
 47	    });
 48	
 49	  const data =
 50	    systemsLoaded &&
 51	    !loadingUsedCapacity &&
 52	    !loadingTotalCapacity &&
 53	    systems.length > 0
 54	      ? systems.map<CapacityMetricDatum>((system) => {
 55	          const { kind, apiGroup, apiVersion } = getGVK(system.spec.kind);
 56	          const usedMetric = getMetricForSystem(usedCapacity, system);
 57	          const totalMetric = getMetricForSystem(totalCapacity, system);
 58	          const datum = {
 59	            name: system.metadata.name,
 60	            namespace: system.metadata.namespace,
 61	            managedSystemName: system.spec.name,
 62	            managedSystemKind: referenceFor(apiGroup)(apiVersion)(kind),
 63	            usedValue: usedMetric
 64	              ? humanizeBinaryBytes(usedMetric?.value?.[1])
 65	              : undefined,
 66	            totalValue: !!totalMetric?.value?.[1]
 67	              ? humanizeBinaryBytes(totalMetric?.value?.[1])
 68	              : undefined,
 69	          };
 70	          return datum;
 71	        })
 72	      : [];
 73	
 74	  // We need to filter storagesystems for which the raw capacity metrics are not applicable (ex: MCG standalone).
 75	  // https://bugzilla.redhat.com/show_bug.cgi?id=2185042
 76	  const filteredData = data.filter((system) => !!system?.totalValue);
 77	  const error =
 78	    !_.isEmpty(systemsLoadError) ||
 79	    !_.isEmpty(errorTotalCapacity) ||
 80	    !_.isEmpty(errorUsedCapacity);
 81	  const isLoading =
 82	    loadingUsedCapacity && loadingTotalCapacity && !systemsLoaded;
 83	
 84	  return (
 85	    <Card className="odf-capacityCard--height">
 86	      <CardHeader>
 87	        <CardTitle>
 88	          {t('System raw capacity')}
 89	          <FieldLevelHelp>{storageCapacityTooltip(t)}</FieldLevelHelp>
 90	        </CardTitle>
 91	      </CardHeader>
 92	      <CardBody>
 93	        {!error ? (
 94	          <CapacityCard
 95	            data={filteredData}
 96	            loading={isLoading}
 97	            resourceModel={ODFStorageSystem}
 98	          />
 99	        ) : (
100	          <>{t('No data available')}</>
101	        )}
102	      </CardBody>
103	    </Card>
104	  );
105	};
106	
107	export default SystemCapacityCard;

